    12→  /// Get the duration since app start
    13→  static Duration? getStartupDuration() {
    14→    if (_startTime == null) return null;
    15→    return DateTime.now().difference(_startTime!);
    16→  }
    17→
    18→  /// Log the startup duration
    19→  static void logStartupDuration() {
    20→    final duration = getStartupDuration();
    21→    if (duration != null && kDebugMode) {
    22→      print('App startup took: ${duration.inMilliseconds}ms');
